// ── Astronomy engine: JD, sun/moon/planet longitude (lines 1355-1556) ──
const _AD=Math.PI/180, _AR=180/Math.PI;
function _n360(a){return((a%360)+360)%360;}
function _n180(a){let v=_n360(a);return v>180?v-360:v;}
function _toJD(y,m,d,h,mi){let Y=y,M=m;if(M<=2){Y--;M+=12;}const A=Math.floor(Y/100),B=2-A+Math.floor(A/4);return Math.floor(365.25*(Y+4716))+Math.floor(30.6001*(M+1))+d+(h+(mi||0)/60)/24+B-1524.5;}

function _sunLon(T){
  // Meeus "Astronomical Algorithms" Ch.25 — precision ~0.01°
  const L0=280.46646+36000.76983*T+0.0003032*T*T;
  const M=357.52911+35999.05029*T-0.0001537*T*T, Mr=M*_AD;
  const C=(1.914602-0.004817*T-0.000014*T*T)*Math.sin(Mr)
        +(0.019993-0.000101*T)*Math.sin(2*Mr)
        +0.000289*Math.sin(3*Mr);
  const O=125.04-1934.136*T;
  return _n360(L0+C-0.00569-0.00478*Math.sin(O*_AD));
}

function _moonLon(T){
  // Meeus Ch.47 — ELP2000/82 truncated, ~40 terms, precision ~0.05°
  const Lp=218.3164477+481267.88123421*T-0.0015786*T*T+T*T*T/538841-T*T*T*T/65194000;
  const D=297.8501921+445267.1114034*T-0.0018819*T*T+T*T*T/545868-T*T*T*T/113065000;
  const M=357.5291092+35999.0502909*T-0.0001536*T*T+T*T*T/24490000;
  const Mp=134.9633964+477198.8675055*T+0.0087414*T*T+T*T*T/69699-T*T*T*T/14712000;
  const F=93.2720950+483202.0175233*T-0.0036539*T*T-T*T*T/3526000+T*T*T*T/863310000;
  const A1=119.75+131.849*T, A2=53.09+479264.290*T, A3=313.45+481266.484*T;
  const E=1-0.002516*T-0.0000074*T*T, E2=E*E;
  const Dr=D*_AD,Mr2=M*_AD,Mpr=Mp*_AD,Fr=F*_AD,A1r=A1*_AD,A2r=A2*_AD,A3r=A3*_AD;
  // Σl (longitude terms) — 60 most significant terms from ELP2000
  let Sl=0;
  Sl+=6288774*Math.sin(Mpr);
  Sl+=1274027*Math.sin(2*Dr-Mpr);
  Sl+=658314*Math.sin(2*Dr);
  Sl+=213618*Math.sin(2*Mpr);
  Sl-=185116*E*Math.sin(Mr2);
  Sl-=114332*Math.sin(2*Fr);
  Sl+=58793*Math.sin(2*Dr-2*Mpr);
  Sl+=57066*E*Math.sin(2*Dr-Mr2-Mpr);
  Sl+=53322*Math.sin(2*Dr+Mpr);
  Sl+=45758*E*Math.sin(2*Dr-Mr2);
  Sl-=40923*E*Math.sin(Mr2-Mpr);
  Sl-=34720*Math.sin(Dr);
  Sl-=30383*E*Math.sin(Mr2+Mpr);
  Sl+=15327*Math.sin(2*Dr-2*Fr);
  Sl-=12528*Math.sin(Mpr+2*Fr);
  Sl+=10980*Math.sin(Mpr-2*Fr);
  Sl+=10675*Math.sin(4*Dr-Mpr);
  Sl+=10034*Math.sin(3*Mpr);
  Sl+=8548*Math.sin(4*Dr-2*Mpr);
  Sl-=7888*E*Math.sin(2*Dr+Mr2-Mpr);
  Sl-=6766*E*Math.sin(2*Dr+Mr2);
  Sl-=5163*Math.sin(Dr-Mpr);
  Sl+=4987*E*Math.sin(Dr+Mr2);
  Sl+=4036*E*Math.sin(2*Dr-Mr2+Mpr);
  Sl+=3994*Math.sin(2*Dr+2*Mpr);
  Sl+=3861*Math.sin(4*Dr);
  Sl+=3665*Math.sin(2*Dr-3*Mpr);
  Sl-=2689*E*Math.sin(Mr2-2*Mpr);
  Sl-=2602*Math.sin(2*Dr-Mpr+2*Fr);
  Sl+=2390*E*Math.sin(2*Dr-Mr2-2*Mpr);
  Sl-=2348*Math.sin(Dr+Mpr);
  Sl+=2236*E2*Math.sin(2*Dr-2*Mr2);
  Sl-=2120*E*Math.sin(Mr2+2*Mpr);
  Sl-=2069*E2*Math.sin(2*Mr2);
  Sl+=2048*E2*Math.sin(2*Dr-2*Mr2-Mpr);
  Sl-=1773*Math.sin(2*Dr+Mpr-2*Fr);
  Sl-=1595*Math.sin(2*Dr+2*Fr);
  Sl+=1215*E*Math.sin(4*Dr-Mr2-Mpr);
  Sl-=1110*Math.sin(2*Mpr+2*Fr);
  Sl-=892*Math.sin(3*Dr-Mpr);
  Sl-=810*E*Math.sin(2*Dr+Mr2+Mpr);
  Sl+=759*E*Math.sin(4*Dr-Mr2-2*Mpr);
  Sl-=713*E2*Math.sin(2*Mr2-Mpr);
  Sl-=700*E2*Math.sin(2*Dr+2*Mr2-Mpr);
  Sl+=691*E*Math.sin(2*Dr+Mr2-2*Mpr);
  Sl+=596*E*Math.sin(2*Dr-Mr2-2*Fr);
  Sl+=549*Math.sin(4*Dr+Mpr);
  Sl+=537*Math.sin(4*Mpr);
  Sl+=520*E*Math.sin(4*Dr-Mr2);
  Sl-=487*Math.sin(Dr-2*Mpr);
  Sl-=399*E*Math.sin(2*Dr+Mr2-2*Fr);
  Sl-=381*Math.sin(2*Mpr-2*Fr);
  // Additional correction terms
  Sl+=3958*Math.sin(A1r)+1962*Math.sin(Lp*_AD-Fr)+318*Math.sin(A2r);
  return _n360(Lp+Sl/1000000);
}

