const NATAL_ASPECTS=[{name:'合',angle:0,orb:8,sym:'☌',good:true},{name:'六合',angle:60,orb:6,sym:'⚹',good:true},{name:'刑',angle:90,orb:7,sym:'□',good:false},{name:'三合',angle:120,orb:8,sym:'△',good:true},{name:'對沖',angle:180,orb:8,sym:'☍',good:false},{name:'半刑',angle:45,orb:2,sym:'∠',good:false},{name:'補半刑',angle:135,orb:2,sym:'⊼',good:false},{name:'五分相',angle:72,orb:2,sym:'Q',good:true},{name:'梅花',angle:150,orb:3,sym:'⚻',good:false}];

// Chiron position (simplified orbit — precision ~1° for 1920-2050)
function _chironLon(T){
  // Chiron orbital period ~50.7 years, high eccentricity (0.38)
  const a=13.648, e=0.3789, I=6.926*_AD;
  const L0=209.39+7.2534*T*100, w0=339.43+1.4230*T*100, Om0=209.21+0.9856*T*100;
  const L=_n360(L0)*_AD, w=_n360(w0)*_AD, Om=_n360(Om0)*_AD;
  const M=L-w; let E=M;
  for(let i=0;i<15;i++) E=E-(E-e*Math.sin(E)-M)/(1-e*Math.cos(E));
  const nu=2*Math.atan2(Math.sqrt(1+e)*Math.sin(E/2),Math.sqrt(1-e)*Math.cos(E/2));
  const r=a*(1-e*Math.cos(E)), ww=w-Om;
  const xh=r*(Math.cos(Om)*Math.cos(nu+ww)-Math.sin(Om)*Math.sin(nu+ww)*Math.cos(I));
  const yh=r*(Math.sin(Om)*Math.cos(nu+ww)+Math.cos(Om)*Math.sin(nu+ww)*Math.cos(I));
  const ea=_planetHelio('Earth',T);
  return _n360(Math.atan2(yh-ea.y,xh-ea.x)*_AR);
}

// Placidus house cusp calculation via semi-arc iteration
function _placidusHouses(asc, mc, obl, geoLat){
  const houses=new Array(12);
  const phi=geoLat*_AD, eps=obl*_AD;
  houses[0]=asc; houses[9]=mc;
  houses[6]=_n360(asc+180); houses[3]=_n360(mc+180);
  
  // Placidus cusp iteration for intermediate cusps
  function placCusp(mc0, frac){
    // Iterative computation of Placidus cusps
    let cusp=_n360(mc0+frac*_n360(asc-mc0));
    for(let iter=0;iter<10;iter++){
      const r=cusp*_AD;
      const D=Math.asin(Math.sin(eps)*Math.sin(r));
      const RASA=Math.atan2(Math.sin(r)*Math.cos(eps),Math.cos(r));
      const MD=Math.abs(_n180(cusp-mc))*_AD;
      const SA=Math.acos(-Math.tan(phi)*Math.tan(D));
      if(isNaN(SA)) break; // extreme latitude fallback
      const target=frac*SA;
      if(Math.abs(MD-target)<0.001) break;
      cusp=_n360(cusp+(target-MD)*_AR*0.5);
    }
    return _n360(cusp);
  }
  
  // Houses 11, 12 (between MC and ASC)
  houses[10]=placCusp(mc, 1/3);
  houses[11]=placCusp(mc, 2/3);
  // Houses 2, 3 (between ASC and IC via opposite)
  houses[1]=_n360(placCusp(_n360(mc+180), 1/3)+180);
  houses[2]=_n360(placCusp(_n360(mc+180), 2/3)+180);
  // Houses 5, 6 (opposite of 11, 12)
  houses[4]=_n360(houses[10]+180);
  houses[5]=_n360(houses[11]+180);
  // Houses 8, 9 already set
  houses[7]=_n360(houses[1]+180);
  houses[8]=_n360(houses[2]+180);
  
  return houses;
}

function computeNatalChart(year,month,day,hour,minute,geoLon,geoLat){
  geoLon=geoLon||120.5; geoLat=geoLat||24.0;
  // UTC轉換 (GMT+8)
  let utH=hour-8, utD=day, utM=month, utY=year, utMi=minute||0;
  if(utH<0){utH+=24;utD--;}
  if(utD<1){utM--;if(utM<1){utM=12;utY--;}utD=new Date(utY,utM,0).getDate();}
  
  const jd=_toJD(utY,utM,utD,utH,utMi), T=(jd-2451545.0)/36525;
  const obl=23.439291-0.013004167*T-0.000000164*T*T+0.000000504*T*T*T; // IAU obliquity
  
  // 行星（高精度）
  const planets={};
  planets['太陽']={lon:_sunLon(T),sym:'☉',color:'#fbbf24'};
  planets['月亮']={lon:_moonLon(T),lat:_moonLat(T),sym:'☽',color:'#94a3b8'};
  [['Mercury','水星','☿','#60a5fa'],['Venus','金星','♀','#4ade80'],['Mars','火星','♂','#f87171'],['Jupiter','木星','♃','#a78bfa'],['Saturn','土星','♄','#d4a017'],['Uranus','天王','♅','#38bdf8'],['Neptune','海王','♆','#818cf8'],['Pluto','冥王','♇','#f472b6']].forEach(([eng,chn,sym,col])=>{planets[chn]={lon:_planetGeoLon(eng,T),sym,color:col};});
  // 月交點（高精度）
  const nnLon=_northNodeLon(T);
  planets['北交']={lon:nnLon,sym:'☊',color:'#a3a3a3'};
  planets['南交']={lon:_n360(nnLon+180),sym:'☋',color:'#737373'};
  // 凱龍星
  planets['凱龍']={lon:_chironLon(T),sym:'⚷',color:'#86efac'};
  
  // 星座資訊
  for(const p of Object.values(planets)){const s=_getSign(p.lon);Object.assign(p,{sign:s.name,signIdx:s.idx,signDeg:s.deg,signSym:s.sym,el:s.el});}
  
  // RAMC / ASC / MC
  const gmst=_n360(280.46061837+360.98564736629*(jd-2451545.0)+0.000387933*T*T-T*T*T/38710000);
  const ramc=_n360(gmst+geoLon);
  const L=ramc*_AD, E=obl*_AD, phi=geoLat*_AD;
  const asc=_n360(Math.atan2(-Math.cos(L),Math.sin(L)*Math.cos(E)+Math.tan(phi)*Math.sin(E))*_AR+180);
  let mc=Math.atan(Math.tan(L)/Math.cos(E))*_AR; const ramcQ=Math.floor(ramc/90);
  if(ramcQ===1||ramcQ===2) mc+=180; mc=_n360(mc);
  
  // Placidus宮位（迭代法）
  let houses;
  try {
    houses=_placidusHouses(asc, mc, obl, geoLat);
  } catch(e) {
    // Fallback: 等分法（極端緯度）
    houses=new Array(12);
    houses[0]=asc; houses[3]=_n360(mc+180); houses[6]=_n360(asc+180); houses[9]=mc;
    for(let q=0;q<4;q++){const s=houses[q*3],ee=houses[((q+1)*3)%12];const span=_n360(ee-s);houses[q*3+1]=_n360(s+span/3);houses[q*3+2]=_n360(s+2*span/3);}
  }
  
  // 行星所在宮位
  for(const p of Object.values(planets)){
    let h=1;
    for(let i=0;i<12;i++){const s=houses[i],e=houses[(i+1)%12];let sp=_n360(e-s),lp=_n360(p.lon-s);if(lp<sp){h=i+1;break;}}
    p.house=h;
  }
  
  // 相位（含主要+次要相位）
  const aspects=[];
  const pKeys=Object.keys(planets);
  for(let i=0;i<pKeys.length;i++)for(let j=i+1;j<pKeys.length;j++){
    const d=Math.abs(_n180(planets[pKeys[i]].lon-planets[pKeys[j]].lon));
    for(const a of NATAL_ASPECTS)if(Math.abs(d-a.angle)<=a.orb){aspects.push({p1:pKeys[i],p2:pKeys[j],type:a.name,sym:a.sym,good:a.good,diff:Math.abs(d-a.angle)});break;}
  }
  
  // 行星逆行判斷
  for(const pn of Object.keys(planets)){
    if(['太陽','月亮','北交','南交'].includes(pn)) continue;
    const dt=0.01;
    let lon2;
    if(pn==='凱龍'){ lon2=_chironLon(T+dt); }
    else {
      const eng={'水星':'Mercury','金星':'Venus','火星':'Mars','木星':'Jupiter','土星':'Saturn','天王':'Uranus','海王':'Neptune','冥王':'Pluto'}[pn];
      lon2=eng?_planetGeoLon(eng,T+dt):planets[pn].lon;
    }
    const diff=_n180(lon2-planets[pn].lon);
    planets[pn].retrograde=diff<0;
    planets[pn].speed=diff/dt; // degrees per century*100 → ~degrees per year
  }
  
  const ascSign=_getSign(asc), mcSign=_getSign(mc);
  
  // 行星力量評估
  const planetStrength={};
  for(const [name,p] of Object.entries(planets)){
    let str=50; // base
    // Domicile (ruling sign)
    const rulers={'太陽':[4],'月亮':[3],'水星':[2,5],'金星':[1,6],'火星':[0,7],'木星':[8,11],'土星':[9,10]};
    if(rulers[name]&&rulers[name].includes(p.signIdx)) str+=20;
    // Exaltation
    const exalt={'太陽':0,'月亮':1,'水星':5,'金星':11,'火星':9,'木星':3,'土星':6};
    if(exalt[name]===p.signIdx) str+=15;
    // Detriment
    const detri={'太陽':10,'月亮':9,'水星':[8,11],'金星':[0,7],'火星':[1,6],'木星':[2,5],'土星':[3,4]};
    const dd=detri[name]; if(dd&&(Array.isArray(dd)?dd.includes(p.signIdx):dd===p.signIdx)) str-=15;
    // Fall
    const fall={'太陽':6,'月亮':7,'水星':11,'金星':5,'火星':3,'木星':9,'土星':0};
    if(fall[name]===p.signIdx) str-=20;
    // Angular house bonus
    if([1,4,7,10].includes(p.house)) str+=10;
    // Retrograde penalty (except nodes)
    if(p.retrograde) str-=10;
    planetStrength[name]=Math.max(0,Math.min(100,str));
  }
  
  const sunSign=planets['太陽'].sign, moonSign=planets['月亮'].sign;
  const summary=`太陽${sunSign}・月亮${moonSign}・上升${ascSign.name}`;
  
  return{planets,houses,aspects,asc,ascSign,mc,mcSign,ramc,jd,T,obl,summary,planetStrength};
}


