      out.why2 = (dashaS.md && dashaS.md.dir === 'pos') ? '目前' + dashaS.md.lord + '大運支持感情發展' : (posEv[1]?posEv[1].text:'大運條件尚可');
      out.why3 = (karakaS[0] && karakaS[0].dir === 'pos') ? karakaS[0].planet + '（愛情代表星）有力' : (posEv[2]?posEv[2].text:'');
      out.riskPoint = negEv.length ? negEv[0].text : '整體無明顯阻礙';
      out.action1 = '主動出擊、參加社交活動，把握當前有利時機';
