      out.why1 = (hlordS[0]) ? '婚姻宮主' + hlordS[0].lord + '：' + hlordS[0].dignity + '，力量中等' : '感情宮位條件中性';
      out.why2 = (negEv[0])?negEv[0].text:'部分因素帶來拉扯';
      out.why3 = (posEv[0])?posEv[0].text:'也有支持的力量存在';
      out.riskPoint = negEv.length >= 2 ? negEv[0].text + '；' + negEv[1].text : (negEv[0]?negEv[0].text:'溝通上可能有障礙');
